using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        var items = new List<int> { 1, 2, 3 };

        var list = new PaginatedList<int>(items, 10, 2, 5);

        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_SetsTotalPages_WithPartialLastPage()
    {
        var items = new List<int> { 1, 2, 3 };

        // 11 items, page size 5 => ceil(11/5) = 3
        var list = new PaginatedList<int>(items, 11, 1, 5);

        Assert.AreEqual(3, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_SetsTotalPages_ExactDivision()
    {
        var items = new List<int> { 1, 2 };

        // 10 items, page size 5 => ceil(10/5) = 2
        var list = new PaginatedList<int>(items, 10, 1, 5);

        Assert.AreEqual(2, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<int> { 1, 2, 3 };

        var list = new PaginatedList<int>(items, 10, 1, 5);

        Assert.AreEqual(3, list.Count);
        CollectionAssert.AreEqual(items, list);
    }

    [TestMethod]
    public void Constructor_ZeroCount_ZeroTotalPages()
    {
        var items = new List<int>();

        var list = new PaginatedList<int>(items, 0, 1, 5);

        Assert.AreEqual(0, list.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // 10 items, page size 5 => 2 pages, on page 2
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        // 10 items, page size 5 => 2 pages, on page 1
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // 3 items, page size 5 => 1 page, on page 1
        var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);

        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 5);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 12).AsQueryable();

        // page 3 of 3, page size 5 => items 11, 12
        var result = PaginatedList<int>.Create(source, 3, 5);

        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(12, result[1]);
        Assert.IsFalse(result.HasNextPage);
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_SinglePage_AllItems()
    {
        var source = Enumerable.Range(1, 3).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    [DataRow(1, false, true, DisplayName = "Page 1 of 3")]
    [DataRow(2, true, true, DisplayName = "Page 2 of 3")]
    [DataRow(3, true, false, DisplayName = "Page 3 of 3")]
    public void Create_PaginationFlags_CorrectForPage(int pageIndex, bool expectedHasPrevious, bool expectedHasNext)
    {
        var source = Enumerable.Range(1, 15).AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex, 5);

        Assert.AreEqual(expectedHasPrevious, result.HasPreviousPage);
        Assert.AreEqual(expectedHasNext, result.HasNextPage);
    }

    [TestMethod]
    public void Create_PageSizeEqualsCount_SinglePage()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_LargePageSize_ReturnsAllOnFirstPage()
    {
        var source = Enumerable.Range(1, 3).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 100);

        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(1, result.TotalPages);
    }
}

