using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class StudentsControllerTests
{
    private static SchoolContext CreateContext(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    private static void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { FirstMidName = "Alice", LastName = "Anderson", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { FirstMidName = "Bob", LastName = "Brown", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { FirstMidName = "Charlie", LastName = "Clark", EnrollmentDate = new DateTime(2019, 9, 1) }
        );
        context.SaveChanges();
    }

    [TestMethod]
    public void Index_DefaultSort_ReturnsStudentsOrderedByLastName()
    {
        using var context = CreateContext(nameof(Index_DefaultSort_ReturnsStudentsOrderedByLastName));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index(null, null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        Assert.AreEqual("Anderson", model[0].LastName);
        Assert.AreEqual("Brown", model[1].LastName);
        Assert.AreEqual("Clark", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_ReturnsStudentsOrderedByLastNameDesc()
    {
        using var context = CreateContext(nameof(Index_NameDescSort_ReturnsStudentsOrderedByLastNameDesc));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index("name_desc", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Clark", model[0].LastName);
        Assert.AreEqual("Brown", model[1].LastName);
        Assert.AreEqual("Anderson", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_ReturnsStudentsOrderedByDateAsc()
    {
        using var context = CreateContext(nameof(Index_DateSort_ReturnsStudentsOrderedByDateAsc));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index("Date", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Clark", model[0].LastName);     // 2019
        Assert.AreEqual("Anderson", model[1].LastName);  // 2020
        Assert.AreEqual("Brown", model[2].LastName);     // 2021
    }

    [TestMethod]
    public void Index_DateDescSort_ReturnsStudentsOrderedByDateDesc()
    {
        using var context = CreateContext(nameof(Index_DateDescSort_ReturnsStudentsOrderedByDateDesc));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index("date_desc", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Brown", model[0].LastName);     // 2021
        Assert.AreEqual("Anderson", model[1].LastName);  // 2020
        Assert.AreEqual("Clark", model[2].LastName);     // 2019
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersStudents()
    {
        using var context = CreateContext(nameof(Index_SearchByLastName_FiltersStudents));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index(null, null, "Brown", null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Brown", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersStudents()
    {
        using var context = CreateContext(nameof(Index_SearchByFirstName_FiltersStudents));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index(null, null, "Alice", null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alice", model[0].FirstMidName);
    }

    [TestMethod]
    public void Index_SearchNoMatch_ReturnsEmpty()
    {
        using var context = CreateContext(nameof(Index_SearchNoMatch_ReturnsEmpty));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index(null, null, "NonExistent", null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Index_NewSearch_ResetsToPage1()
    {
        using var context = CreateContext(nameof(Index_NewSearch_ResetsToPage1));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Passing searchString (non-null) resets page to 1
        var result = controller.Index(null, null, "A", null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_CurrentFilter_MaintainsFilterAcrossPages()
    {
        using var context = CreateContext(nameof(Index_CurrentFilter_MaintainsFilterAcrossPages));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // When searchString is null, currentFilter is used
        var result = controller.Index(null, "Anderson", null, 1) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Anderson", model[0].LastName);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters_Default()
    {
        using var context = CreateContext(nameof(Index_SetsViewBagSortParameters_Default));
        using var controller = new StudentsController(context);

        controller.Index(null, null, null, null);

        Assert.AreEqual("name_desc", controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters_WhenNameDescActive()
    {
        using var context = CreateContext(nameof(Index_SetsViewBagSortParameters_WhenNameDescActive));
        using var controller = new StudentsController(context);

        controller.Index("name_desc", null, null, null);

        // When sortOrder is "name_desc", NameSortParm should be "" (toggle back to asc)
        Assert.AreEqual("", controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters_WhenDateActive()
    {
        using var context = CreateContext(nameof(Index_SetsViewBagSortParameters_WhenDateActive));
        using var controller = new StudentsController(context);

        controller.Index("Date", null, null, null);

        Assert.AreEqual("name_desc", controller.ViewBag.NameSortParm);
        Assert.AreEqual("date_desc", controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsStudent()
    {
        using var context = CreateContext(nameof(Details_ValidId_ReturnsStudent));
        var student = new Student { FirstMidName = "Test", LastName = "Student", EnrollmentDate = DateTime.Today };
        context.Students.Add(student);
        context.SaveChanges();
        using var controller = new StudentsController(context);

        var result = controller.Details(student.ID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Student", model.LastName);
        Assert.AreEqual("Test", model.FirstMidName);
    }

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        using var context = CreateContext(nameof(Details_NullId_ReturnsBadRequest));
        using var controller = new StudentsController(context);

        var result = controller.Details(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ThrowsInvalidOperationException()
    {
        using var context = CreateContext(nameof(Details_InvalidId_ThrowsInvalidOperationException));
        using var controller = new StudentsController(context);

        // .Single() throws when sequence has no matching elements
        Assert.ThrowsException<InvalidOperationException>(() => controller.Details(999));
    }

    [TestMethod]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        using var context = CreateContext(nameof(Create_Get_ReturnsViewWithDefaultDate));
        using var controller = new StudentsController(context);

        var result = controller.Create() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidModel_SavesAndRedirects()
    {
        using var context = CreateContext(nameof(Create_Post_ValidModel_SavesAndRedirects));
        using var controller = new StudentsController(context);
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = controller.Create(student) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(1, context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_ValidModel_SetsStudentProperties()
    {
        using var context = CreateContext(nameof(Create_Post_ValidModel_SetsStudentProperties));
        using var controller = new StudentsController(context);
        var student = new Student
        {
            FirstMidName = "Jane",
            LastName = "Doe",
            EnrollmentDate = new DateTime(2023, 1, 15)
        };

        controller.Create(student);

        var saved = context.Students.First();
        Assert.AreEqual("Jane", saved.FirstMidName);
        Assert.AreEqual("Doe", saved.LastName);
        Assert.AreEqual(new DateTime(2023, 1, 15), saved.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_MinValueDate_AddsModelError()
    {
        using var context = CreateContext(nameof(Create_Post_MinValueDate_AddsModelError));
        using var controller = new StudentsController(context);
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        var result = controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(controller.ModelState.ContainsKey("EnrollmentDate"));
        Assert.AreEqual(0, context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_DefaultDate_AddsModelError()
    {
        using var context = CreateContext(nameof(Create_Post_DefaultDate_AddsModelError));
        using var controller = new StudentsController(context);
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Student",
            EnrollmentDate = default(DateTime)
        };

        var result = controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_DateBeforeSqlMin_AddsModelError()
    {
        using var context = CreateContext(nameof(Create_Post_DateBeforeSqlMin_AddsModelError));
        using var controller = new StudentsController(context);
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Student",
            EnrollmentDate = new DateTime(1000, 1, 1)
        };

        var result = controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        using var context = CreateContext(nameof(Create_Post_InvalidModelState_ReturnsView));
        using var controller = new StudentsController(context);
        controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "New",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(0, context.Students.Count());
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        using var context = CreateContext(nameof(Edit_Get_ValidId_ReturnsViewWithStudent));
        var student = new Student { FirstMidName = "Test", LastName = "Student", EnrollmentDate = DateTime.Today };
        context.Students.Add(student);
        context.SaveChanges();
        using var controller = new StudentsController(context);

        var result = controller.Edit(student.ID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Student", model.LastName);
    }

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        using var context = CreateContext(nameof(Edit_Get_NullId_ReturnsBadRequest));
        using var controller = new StudentsController(context);

        var result = controller.Edit((int?)null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        using var context = CreateContext(nameof(Edit_Get_InvalidId_ReturnsNotFound));
        using var controller = new StudentsController(context);

        var result = controller.Edit(999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Post_ValidModel_UpdatesAndRedirects()
    {
        using var context = CreateContext(nameof(Edit_Post_ValidModel_UpdatesAndRedirects));
        var student = new Student { FirstMidName = "Test", LastName = "Original", EnrollmentDate = DateTime.Today };
        context.Students.Add(student);
        context.SaveChanges();
        context.Entry(student).State = EntityState.Detached;
        using var controller = new StudentsController(context);
        var editedStudent = new Student
        {
            ID = student.ID,
            FirstMidName = "Updated",
            LastName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = controller.Edit(editedStudent) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_MinValueDate_AddsModelError()
    {
        using var context = CreateContext(nameof(Edit_Post_MinValueDate_AddsModelError));
        using var controller = new StudentsController(context);
