    [TestMethod]
    public void Index_Paging_ReturnsCorrectPageSize()
    {
        using var context = CreateContext(nameof(Index_Paging_ReturnsCorrectPageSize));
        // Add 15 students to exceed page size of 10
        for (int i = 0; i < 15; i++)
        {
            context.Students.Add(new Student
            {
                FirstMidName = $"Student{i:D2}",
                LastName = $"Last{i:D2}",
                EnrollmentDate = DateTime.Today
            });
        }
        context.SaveChanges();
        using var controller = new StudentsController(context);

        var result = controller.Index(null, null, null, 1) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(10, model.Count);  // page size is 10
        Assert.IsTrue(model.HasNextPage);
        Assert.IsFalse(model.HasPreviousPage);
    }

    [TestMethod]
    public void Index_Paging_SecondPage_ReturnRemainingStudents()
    {
        using var context = CreateContext(nameof(Index_Paging_SecondPage_ReturnRemainingStudents));
        for (int i = 0; i < 15; i++)
        {
            context.Students.Add(new Student
            {
                FirstMidName = $"Student{i:D2}",
                LastName = $"Last{i:D2}",
                EnrollmentDate = DateTime.Today
            });
        }
        context.SaveChanges();
        using var controller = new StudentsController(context);

        var result = controller.Index(null, null, null, 2) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(5, model.Count);  // 15 - 10 = 5 remaining
        Assert.IsFalse(model.HasNextPage);
        Assert.IsTrue(model.HasPreviousPage);
