using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class StudentsControllerTests
{
    private static SchoolContext CreateContext(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    private static void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { FirstMidName = "Alice", LastName = "Anderson", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { FirstMidName = "Bob", LastName = "Brown", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { FirstMidName = "Charlie", LastName = "Clark", EnrollmentDate = new DateTime(2019, 9, 1) }
        );
        context.SaveChanges();
    }

    [TestMethod]
    public void Index_DefaultSort_ReturnsStudentsOrderedByLastName()
    {
        using var context = CreateContext(nameof(Index_DefaultSort_ReturnsStudentsOrderedByLastName));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index(null, null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        Assert.AreEqual("Anderson", model[0].LastName);
        Assert.AreEqual("Brown", model[1].LastName);
        Assert.AreEqual("Clark", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_ReturnsStudentsOrderedByLastNameDesc()
    {
        using var context = CreateContext(nameof(Index_NameDescSort_ReturnsStudentsOrderedByLastNameDesc));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index("name_desc", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Clark", model[0].LastName);
        Assert.AreEqual("Brown", model[1].LastName);
        Assert.AreEqual("Anderson", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_ReturnsStudentsOrderedByDateAsc()
    {
        using var context = CreateContext(nameof(Index_DateSort_ReturnsStudentsOrderedByDateAsc));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index("Date", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Clark", model[0].LastName);     // 2019
        Assert.AreEqual("Anderson", model[1].LastName);  // 2020
        Assert.AreEqual("Brown", model[2].LastName);     // 2021
    }

    [TestMethod]
    public void Index_DateDescSort_ReturnsStudentsOrderedByDateDesc()
    {
        using var context = CreateContext(nameof(Index_DateDescSort_ReturnsStudentsOrderedByDateDesc));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index("date_desc", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Brown", model[0].LastName);     // 2021
        Assert.AreEqual("Anderson", model[1].LastName);  // 2020
        Assert.AreEqual("Clark", model[2].LastName);     // 2019
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersStudents()
    {
        using var context = CreateContext(nameof(Index_SearchByLastName_FiltersStudents));
        SeedStudents(context);
        using var controller = new StudentsController(context);

        var result = controller.Index(null, null, "Brown", null) as ViewResult;

