    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    private static Instructor SeedInstructor(SchoolContext context)
    {
        var instructor = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = new DateTime(1995, 3, 11),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();
        return instructor;
    }

    [TestMethod]
    public void Index_ReturnsAllDepartments()
    {
        using var context = CreateContext(nameof(Index_ReturnsAllDepartments));
        var instructor = SeedInstructor(context);
        context.Departments.AddRange(
            new Department { Name = "English", Budget = 350000, StartDate = DateTime.Today, InstructorID = instructor.ID },
            new Department { Name = "Math", Budget = 100000, StartDate = DateTime.Today }
        );
        context.SaveChanges();
        using var controller = new DepartmentsController(context);

        var result = controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        using var context = CreateContext(nameof(Index_EmptyDatabase_ReturnsEmptyList));
