using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class InstructorsControllerTests
{
    private static SchoolContext CreateContext(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    private static (Instructor Instructor, Department Dept, Course Course1, Course Course2) SeedFullData(SchoolContext context)
    {
        var dept = new Department { Name = "Engineering", Budget = 350000, StartDate = DateTime.Today };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
        var course2 = new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID };
        context.Courses.AddRange(course1, course2);
        context.SaveChanges();

        var instructor = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = new DateTime(1995, 3, 11),
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = course1.CourseID }
            },
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        // Set department admin
        dept.InstructorID = instructor.ID;
        context.SaveChanges();

        return (instructor, dept, course1, course2);
    }

    [TestMethod]
    public void Index_NoSelection_ReturnsAllInstructors()
    {
        using var context = CreateContext(nameof(Index_NoSelection_ReturnsAllInstructors));
        var dept = new Department { Name = "Test", Budget = 100000, StartDate = DateTime.Today };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 101, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        context.Instructors.AddRange(
            new Instructor
            {
                FirstMidName = "Alice", LastName = "Smith", HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>
                {
                    new CourseAssignment { CourseID = course.CourseID }
                }
            },
            new Instructor
            {
                FirstMidName = "Bob", LastName = "Jones", HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
            }
        );
        context.SaveChanges();
        using var controller = new InstructorsController(context);

        var result = controller.Index(null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_SelectedInstructor_PopulatesCourses()
    {
        using var context = CreateContext(nameof(Index_SelectedInstructor_PopulatesCourses));
        var (instructor, dept, course1, course2) = SeedFullData(context);
        using var controller = new InstructorsController(context);

        var result = controller.Index(instructor.ID, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count()); // instructor has 1 course assignment
    }

    [TestMethod]
