            new Instructor
            {
                FirstMidName = "Alice", LastName = "Smith", HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>
                {
                    new CourseAssignment { CourseID = course.CourseID }
                }
            },
            new Instructor
            {
                FirstMidName = "Bob", LastName = "Jones", HireDate = DateTime.Today,
                CourseAssignments = new List<CourseAssignment>()
