using System;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private static SchoolContext CreateContext(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    [TestInitialize]
    public void Setup()
    {
        // Drain any leftover notifications from the static queue
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsEmptyNotifications()
    {
        using var context = CreateContext(nameof(GetNotifications_EmptyQueue_ReturnsEmptyNotifications));
        using var controller = new NotificationsController(context);

        var result = controller.GetNotifications();

        Assert.IsNotNull(result);
        var jsonResult = result as JsonResult;
        Assert.IsNotNull(jsonResult);
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        using var context = CreateContext(nameof(GetNotifications_WithNotifications_ReturnsNotifications));
        // Pre-load the static queue with notifications
        using var service = new NotificationService();
        service.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);
        service.SendNotification("Course", "101", "Math", EntityOperation.UPDATE);
        using var controller = new NotificationsController(context);

        var result = controller.GetNotifications();

        Assert.IsNotNull(result);
        Assert.IsInstanceOfType(result, typeof(JsonResult));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        using var context = CreateContext(nameof(GetNotifications_LimitsTo10));
        // Pre-load the static queue with 15 notifications
        using var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
        }
        using var controller = new NotificationsController(context);

        // Call GetNotifications - should stop at 10
        var result = controller.GetNotifications() as JsonResult;
        Assert.IsNotNull(result);

        // Verify that there are still notifications in the queue (5 remaining)
        int remaining = 0;
        while (service.ReceiveNotification() != null) remaining++;
        Assert.AreEqual(5, remaining);
    }

    [TestMethod]
    public void MarkAsRead_ReturnsJsonSuccess()
    {
        using var context = CreateContext(nameof(MarkAsRead_ReturnsJsonSuccess));
        using var controller = new NotificationsController(context);

        var result = controller.MarkAsRead(1);

        Assert.IsNotNull(result);
        Assert.IsInstanceOfType(result, typeof(JsonResult));
    }

    [TestMethod]
    public void MarkAsRead_InvalidId_StillReturnsSuccess()
    {
        using var context = CreateContext(nameof(MarkAsRead_InvalidId_StillReturnsSuccess));
        using var controller = new NotificationsController(context);

        // MarkAsRead is a no-op in the in-memory implementation
        var result = controller.MarkAsRead(-1);

        Assert.IsNotNull(result);
        Assert.IsInstanceOfType(result, typeof(JsonResult));
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        using var context = CreateContext(nameof(Index_ReturnsView));
        using var controller = new NotificationsController(context);

        var result = controller.Index() as ViewResult;

        Assert.IsNotNull(result);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using System;

namespace ContosoUniversity.Tests;

/// <summary>
/// Tests for the abstract BaseController through a concrete test subclass.
/// </summary>
[TestClass]
public sealed class BaseControllerTests
{
    private static SchoolContext CreateContext(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Concrete subclass to test the abstract BaseController's protected methods.
    /// </summary>
    private sealed class TestableController : BaseController
    {
        public TestableController(SchoolContext context) : base(context) { }

        public void InvokeSendEntityNotification(string entityType, string entityId, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, operation);
        }

        public void InvokeSendEntityNotification(string entityType, string entityId, string displayName, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, displayName, operation);
        }

        public SchoolContext GetDb() => db;
        public NotificationService GetNotificationService() => notificationService;
    }

    [TestInitialize]
    public void Setup()
    {
        // Drain any leftover notifications from the static queue
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    [TestMethod]
    public void Constructor_SetsDbContext()
    {
        using var context = CreateContext(nameof(Constructor_SetsDbContext));
        using var controller = new TestableController(context);

        Assert.AreSame(context, controller.GetDb());
    }

    [TestMethod]
    public void Constructor_InitializesNotificationService()
    {
        using var context = CreateContext(nameof(Constructor_InitializesNotificationService));
        using var controller = new TestableController(context);

        Assert.IsNotNull(controller.GetNotificationService());
    }

    [TestMethod]
    public void SendEntityNotification_WithoutDisplayName_EnqueuesNotification()
    {
        using var context = CreateContext(nameof(SendEntityNotification_WithoutDisplayName_EnqueuesNotification));
        using var controller = new TestableController(context);

        controller.InvokeSendEntityNotification("Student", "1", EntityOperation.CREATE);

        // Verify notification was enqueued
        using var service = new NotificationService();
        var notification = service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("System", notification.CreatedBy); // default user
    }

    [TestMethod]
    public void SendEntityNotification_WithDisplayName_EnqueuesNotification()
    {
        using var context = CreateContext(nameof(SendEntityNotification_WithDisplayName_EnqueuesNotification));
        using var controller = new TestableController(context);

        controller.InvokeSendEntityNotification("Course", "101", "Mathematics", EntityOperation.UPDATE);

        using var service = new NotificationService();
        var notification = service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course", notification.EntityType);
        Assert.AreEqual("101", notification.EntityId);
        Assert.IsTrue(notification.Message.Contains("Mathematics"));
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendEntityNotification_DoesNotThrow_OnError()
    {
        // BaseController wraps SendNotification in try/catch
        // Even if something goes wrong, it should not throw
        using var context = CreateContext(nameof(SendEntityNotification_DoesNotThrow_OnError));
        using var controller = new TestableController(context);

        // This should not throw
        controller.InvokeSendEntityNotification("Test", "1", EntityOperation.DELETE);
        controller.InvokeSendEntityNotification("Test", "1", null, EntityOperation.CREATE);
    }

    [TestMethod]
    public void Dispose_DisposesResources()
    {
        var context = CreateContext(nameof(Dispose_DisposesResources));
        var controller = new TestableController(context);

        controller.Dispose();

        // After dispose, context should be disposed (will throw on use)
        Assert.ThrowsException<ObjectDisposedException>(() => context.Students.ToListAsync().Wait());
    }
}

